    '/root/depiflash': 'depiflash',
    '/root/magnolia-peluqueria': 'magnolia-peluqueria',
    '/root/luis-de-leon-concept': 'luis-de-leon-concept',
    '/root/paragu-ai-builder': 'paragu-ai-builder',
}

for local, name in repos.items():
    p = Path(local) / '.github/workflows'
    wfs = sorted(p.glob('*.yml')) if p.exists() else []

    so = subprocess.run(
        ['gh', 'api', f'/repos/Ai-Whisperers/{name}/actions/workflows', '--jq', '.workflows[] | "\(.name): \(.state) (path=\(.path))"'],
        text=True, capture_output=True, timeout=30
    )

    print(f'\n## {name}')
    if so.returncode != 0:
        print(f'  ERROR: {so.stderr.strip()}')
    else:
        for line in so.stdout.strip().splitlines():
            print(f'  {line}')

    # Check latest run status
    ro = subprocess.run(
